    #[test]
    fn arm64_emitter_accepts_only_arm64_source_architecture() {
        let entry_artifact = entry_artifact();
        let proof = proof();
        let arm_buffer = frozen_buffer(AssemblerArchitecture::Arm64);
        let arm_image = source_image(&arm_buffer);
        let arm_linked = linked_image(&arm_buffer, &arm_image);

        let record = record_baseline_machine_code_emission(request_with_emitter(
            BaselineMachineCodeEmitterKind::P6Arm64NoCallNoHeapReturnSeedSubset,
            &entry_artifact,
            &proof,
            &arm_buffer,
            &arm_image,
            Some(&arm_linked),
        ))
        .expect("ARM64 emitter accepts ARM64 source bytes");
        assert_eq!(
            record.emitter_kind,
            BaselineMachineCodeEmitterKind::P6Arm64NoCallNoHeapReturnSeedSubset
        );
        assert_eq!(record.source_architecture, AssemblerArchitecture::Arm64);

        let x86_buffer = frozen_buffer(AssemblerArchitecture::X86_64);
        let x86_image = source_image(&x86_buffer);
        let x86_linked = linked_image(&x86_buffer, &x86_image);
        assert_eq!(
            record_baseline_machine_code_emission(request_with_emitter(
                BaselineMachineCodeEmitterKind::P6Arm64NoCallNoHeapReturnSeedSubset,
                &entry_artifact,
                &proof,
                &x86_buffer,
                &x86_image,
                Some(&x86_linked),
            )),
            Err(
                BaselineMachineCodeEmissionValidationError::SourceArchitectureMismatch {
                    expected: AssemblerArchitecture::Arm64,
                    actual: Some(AssemblerArchitecture::X86_64),
                },
            )
        );
    }

    #[test]
    fn relocation_count_nonzero_is_rejected() {
        let entry_artifact = entry_artifact();
        let proof = proof();
        let clean_buffer = frozen_buffer(AssemblerArchitecture::X86_64);
        let clean_image = source_image(&clean_buffer);
        let linked = linked_image(&clean_buffer, &clean_image);
        let relocated_buffer = frozen_buffer_with_relocation();
        let relocated_image = source_image(&relocated_buffer);

        assert_eq!(
            record_baseline_machine_code_emission(request(
                &entry_artifact,
                &proof,
                &relocated_buffer,
                &relocated_image,
                Some(&linked),
            )),
            Err(
                BaselineMachineCodeEmissionValidationError::RelocationsUnsupported {
                    source: BaselineMachineCodeEmissionRelocationSource::SourceBuffer,
                    actual: 1,
                },
            )
        );

        let (entry_artifact, proof, buffer, image, mut linked) = accepted_parts();
        linked.relocation_count = 1;
        assert_eq!(
            record_baseline_machine_code_emission(request(
                &entry_artifact,
                &proof,
                &buffer,
                &image,
                Some(&linked),
            )),
            Err(
                BaselineMachineCodeEmissionValidationError::RelocationsUnsupported {
                    source: BaselineMachineCodeEmissionRelocationSource::LinkedImage,
                    actual: 1,
                },
            )
        );
    }

    #[test]
    fn linked_digest_or_length_mismatch_is_rejected() {
        let (entry_artifact, proof, buffer, image, mut linked) = accepted_parts();
        linked.output_digest = AssemblerByteImageDigest(0xfeed);

        assert_eq!(
            record_baseline_machine_code_emission(request(
                &entry_artifact,
                &proof,
                &buffer,
                &image,
                Some(&linked),
            )),
            Err(
                BaselineMachineCodeEmissionValidationError::LinkedImageInvalid {
                    error: AssemblerValidationError::AssemblerByteImageDigestMismatch {
                        expected: AssemblerByteImageDigest(0xfeed),
                        actual: image.digest(),
                    },
                },
            )
        );

        let (entry_artifact, proof, buffer, image, mut linked) = accepted_parts();
        linked.output_size_bytes += 1;
        assert_eq!(
            record_baseline_machine_code_emission(request(
                &entry_artifact,
                &proof,
                &buffer,
                &image,
                Some(&linked),
            )),
            Err(
                BaselineMachineCodeEmissionValidationError::LinkedImageInvalid {
                    error: AssemblerValidationError::AssemblerByteImageBytesLengthMismatch {
                        expected: CALLER_SUPPLIED_RECORD_BYTES.len() as u32 + 1,
                        actual: CALLER_SUPPLIED_RECORD_BYTES.len(),
                    },
                },
            )
        );
    }

    #[test]
    fn writable_machine_code_metadata_is_accepted_as_byte_shape_provenance() {
        let (mut entry_artifact, proof, buffer, image, linked) = accepted_parts();
        entry_artifact.machine_code.protection = ExecutableMemoryProtection::Writable;
        entry_artifact.machine_code.lifecycle = ExecutableAllocationLifecycle::AllocatedWritable;

        let record = record_baseline_machine_code_emission(request(
            &entry_artifact,
            &proof,
            &buffer,
            &image,
            Some(&linked),
        ))
        .unwrap();

        assert_eq!(
            record.machine_code.protection,
            ExecutableMemoryProtection::Writable
        );
        assert_eq!(
            record.machine_code.lifecycle,
            ExecutableAllocationLifecycle::AllocatedWritable
        );
        assert_eq!(record.validate(), Ok(()));
    }

