    #[test]
    fn unsupported_opcode_subset_or_effect_contract_is_rejected() {
        let entry_artifact = entry_artifact();
        let proof = proof_for_subset(
            BaselineSupportedOpcodeSubset::P6ConstantsMovesReturnInt32ArithmeticBitwise,
        );
        let buffer = frozen_buffer(AssemblerArchitecture::X86_64);
        let image = source_image(&buffer);
        let linked = linked_image(&buffer, &image);

        assert_eq!(
            record_baseline_machine_code_emission(request(
                &entry_artifact,
                &proof,
                &buffer,
                &image,
                Some(&linked),
            )),
            Err(
                BaselineMachineCodeEmissionValidationError::UnsupportedOpcodeSubset {
                    emitter: BaselineMachineCodeEmitterKind::P6X86_64NoCallNoHeapSubset,
                    expected: BaselineSupportedOpcodeSubset::P6ConstantsMovesReturnInt32Arithmetic,
                    actual:
                        BaselineSupportedOpcodeSubset::P6ConstantsMovesReturnInt32ArithmeticBitwise,
                },
            )
        );

        let (entry_artifact, proof, buffer, image, linked) = accepted_parts();
        let mut record = record_baseline_machine_code_emission(request(
            &entry_artifact,
            &proof,
            &buffer,
            &image,
            Some(&linked),
        ))
        .unwrap();
        record.effect_contract.summary.may_call_js = true;
        record.proof.effect_contract = record.effect_contract;

        assert_eq!(
            record.validate(),
            Err(
                BaselineMachineCodeEmissionValidationError::UnsupportedEffectContract {
                    emitter: BaselineMachineCodeEmitterKind::P6X86_64NoCallNoHeapSubset,
                    expected: BaselineSupportedOpcodeSubset::P6ConstantsMovesReturnInt32Arithmetic
                        .generated_effect_contract(),
                    actual: record.effect_contract,
                },
            )
        );
    }
